exploreUrl:
@js:
sort=[];
function push(title,url,type1,type2){
	var item={title:title,url:url};
	item.style={layout_flexGrow:type1,layout_flexBasisPercent:type2};
	sort.push(item)
};
const page="<,page/{{page}}/>";
const categories=[
	["全部","/",1,1],
	["两性关系","/category/love/"],
	["福利资源","/category/fuli/"],
	["每日福利","/category/daily/"],
	["学习资料","/category/study/"],
	["佳软","/category/soft/"],
	["子站","",1,1],
	["泡吧","https://pao8.life/"],
	["色聚","https://seju.life/"],
	["吃瓜","https://1gua.xyz/"],
	["妹子","https://1mei.live/"],
	["探花","https://1tanhua.xyz/"],
	["直播","https://1zhibo.xyz/"],
	["ASMR","https://1asmr.xyz/"]
];
categories.forEach(item=>{
	const [title,basePath,type1,type2]=item;
	const url=basePath?basePath+page:"";
	if (item.length===4){
		push(title,url,type1,type2)
	}else{
		push(title,url)
	}
});
JSON.stringify(sort)
